/* Local DOMPurify fallback loader.
 * This bundle only provides a local marker and fallback wiring.
 * If DOMPurify is already present (for example from an external script source),
 * this file remains inert; if not, app.js detects absence and warns about
 * degraded sanitization behavior.
 */
(function () {
  if (typeof window === 'undefined' || typeof window.DOMPurify !== 'undefined') {
    return;
  }
  // Keep explicit marker for diagnostics.
  window.__domPurifyBundleLoaded = true;
})();
